(self.webpackChunkcheatsheet=self.webpackChunkcheatsheet||[]).push([[2193],{7794:(e,i,t)=>{"use strict";t.r(i),t.d(i,{data:()=>a});const a={key:"v-69e0d34a",path:"/git/commit/ignore/",title:"Ignore a file",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"ทำไมต้องไม่สนใจไฟล์",slug:"ทําไมต้องไม่สนใจไฟล์",children:[]},{level:2,title:"การไม่สนใจไฟล์",slug:"การไม่สนใจไฟล์",children:[]}],filePathRelative:"git/commit/ignore/README.md",git:{updatedTime:162676698e4,contributors:[]}}},1957:(e,i,t)=>{"use strict";t.r(i),t.d(i,{default:()=>r});const a=(0,t(6252).uE)('<h1 id="ignore-a-file" tabindex="-1"><a class="header-anchor" href="#ignore-a-file" aria-hidden="true">#</a> Ignore a file</h1><h2 id="ทําไมต้องไม่สนใจไฟล์" tabindex="-1"><a class="header-anchor" href="#ทําไมต้องไม่สนใจไฟล์" aria-hidden="true">#</a> ทำไมต้องไม่สนใจไฟล์</h2><p>การทำ ignore คือการยกเลิกไม่ให้ git ทำ version control กับไฟล์ที่เราไม่เคยต้องการให้จัดเก็บ หรือทำเวอร์ชัน</p><p>ตัวอย่างไฟล์ที่ไม่ควรทำ versioning</p><ul><li>ไฟล์ binary / execute ขนาดใหญ่</li><li>ไฟล์ log</li><li>ไฟล์ที่ใช้ในการสนับสนุนการ precompile</li><li>ไฟล์ที่เป็นของระบบปฎิบัติการ</li><li>ไฟล์ที้มีขนาดใหญ่</li></ul><p>ไฟล์ที่มีขนาดให่ญ่เกิน 100MB จะไม่สามารถอับขื้น GitHub ได้ เนื่องจาก Git ไม่ได้ทำไว้สำหรับการทำ versioning ไฟล์ขนาดใหญ่ (เพราะ Git ต้องเทียบไฟล์ทีละบรรทัด แล้วไฟล์ขนาดใหญ่มากๆ ก็จะใช้เวลาเทียบมาก)</p><p>หากต้องการที่จะอับโหลดไฟล์ขนาดใหญ่ (เช่นไฟล์ .exe) ก็แนะนำให้อับโหลดขื้น <a href="">Release</a> เพื่อทำการจัดเก็บอีกแบบ (ซึ่งจะมีข้อจำกัดขนาดอยู่ที่ 2GB)</p><h2 id="การไม่สนใจไฟล์" tabindex="-1"><a class="header-anchor" href="#การไม่สนใจไฟล์" aria-hidden="true">#</a> การไม่สนใจไฟล์</h2><p>โดยจะต้องสร้างไฟล์ <code>.gitignore</code> เพื่อทำการเขียนรายชื่อไฟล์ หรือโฟลเดอร์ที่เราไม่สนใจ</p>',9),r={render:function(e,i){return a}}}}]);